/*
 * The vDSO data page.
 *
 * Dynamically allocated to accommodate variable aux clock counts.
 * The allocation is always PAGE_SIZE, mapped as a single page to userspace.
 * aux_clock_data[] is a flexible array member; num_aux_clocks determines
 * how many entries are valid.
 */
#ifdef CONFIG_GENERIC_GETTIMEOFDAY
struct vdso_time_data *vdso_k_time_data __ro_after_init;

static int __init vdso_time_data_init(void)
{
	struct vdso_time_data *vdata;
	unsigned int num_aux = MAX_AUX_CLOCKS;

	vdata = (struct vdso_time_data *)__get_free_page(GFP_KERNEL);
	if (!vdata)
		return -ENOMEM;

	vdata->num_aux_clocks = num_aux;
	vdso_k_time_data = vdata;
	return 0;
}
subsys_initcall(vdso_time_data_init);
#endif /* CONFIG_GENERIC_GETTIMEOFDAY */

input.newString:
/*
 * The vDSO data page.
 *
 * Statically allocated with space for MAX_AUX_CLOCKS aux clocks, but only
 * num_aux_clocks entries are actively used (variable clock counts).  A
 * flexible array member (aux_clock_data[]) is used so that other allocators
 * (e.g. time namespaces) can allocate exactly the required number of slots.
 */
#ifdef CONFIG_GENERIC_GETTIMEOFDAY
struct vdso_time_data_alloc {
	struct vdso_time_data	vdata;
	struct vdso_clock	aux_clock_data[MAX_AUX_CLOCKS];
} __page_aligned_data;

static struct vdso_time_data_alloc vdso_time_data_store;
struct vdso_time_data *vdso_k_time_data = &vdso_time_data_store.vdata;
static_assert(sizeof(struct vdso_time_data_alloc) <= PAGE_SIZE);
#endif /* CONFIG_GENERIC_GETTIMEOFDAY */

